INSERT IGNORE INTO ptype (id, pregunta, respuesta, categoria) VALUES ('11604','6) ¿Por qué es crucial seleccionar el tipo de dato adecuado para una clave primaria en una base de datos relacional?','b. Para asegurar la eficiencia en el uso de espacio de almacenamiento y la velocidad de acceso a los datos.','2026');
