INSERT IGNORE INTO ptype (id, pregunta, respuesta, categoria) VALUES ('11696','¿Cuál de las siguientes opciones describe correctamente la relación entre estructuras de control y bloques de código en la programación?','c. Las estructuras de control utilizan bloques de código para agrupar múltiples instrucciones, permitiendo la ejecución condicional o repetitiva de éstas.','2026');
