INSERT IGNORE INTO ptype (id, pregunta, respuesta, categoria) VALUES ('11697','2)¿Cuál de las siguientes afirmaciones es verdadera respecto a las conversiones de tipo en lenguajes de programación como Java?','d. Una conversión explícita (casting) es necesaria cuando se asigna un valor de un tipo de dato de mayor capacidad a un tipo de menor capacidad para evitar la pérdida de información.','2026');
