</xsl:template>
<xsl:template match="libro">
<div>Plantilla 1</div>
</xsl:template
<xsl:template match="libro[@categoria=''ficcion'']" priority="2">
<div>Plantilla 2</div>
</xsl:template>
<xsl:template name="libroFiccion">
<div>Plantilla 3</div>
</xsl:template>
</xsl:stylesheet>
