BEGIN TRANSACTION;
-- Inserción de un nuevo empleado utilizando datos proporcionados
VALUES (''Juan Pérez'', (SELECT ID FROM Departamento WHERE Nombre = ''Desarrollo''), 30000);
-- Actualización del salario de todos los empleados del departamento de ''Desarrollo'' en un 10%
UPDATE Empleado
SET Salario = Salario * 1.10
WHERE DepartamentoID = (SELECT ID FROM Departamento WHERE Nombre = ''Desarrollo'');
-- Borrado de empleados que no han sido asignados a ningún proyecto
DELETE FROM Empleado
WHERE ID NOT IN (SELECT EmpleadoID FROM ProyectoEmpleado);
COMMIT;
