CREATE PROCEDURE RegistrarPrestamo(
IN LibroID INT,
IN UsuarioID INT,
IN FechaDevolucion DATE
)
BEGIN
DECLARE EstadoLibro VARCHAR(20);
-- Comprobar el estado actual del libro
SELECT Estado INTO EstadoLibro FROM Libros WHERE ID = LibroID;
IF EstadoLibro = ''Disponible'' THEN
-- Actualizar el estado del libro a ''Prestado''
UPDATE Libros SET Estado = ''Prestado'' WHERE ID = LibroID;
-- Registrar el préstamo
VALUES (LibroID, UsuarioID, CURDATE(), FechaDevolucion);
ELSE
SIGNAL SQLSTATE ''45000'' SET MESSAGE_TEXT = ''El libro no está disponible para préstamo.'';
END IF;
END;

